  "exercise_summary": "הפעלת PUT לעדכון ממוצע ציונים של סטודנט קיים לפי ת\"ז. מחייב אימות תקפות ת\"ז (10 ספרות), תקפות ממוצע (0-100), בדיקת קיומם של הסטודנט במאגר, עדכון הממוצע, והחזרת תשובת הצלחה או שגיאה.",
  "task_ids": [
    "Q3/4-PUT.api_validation",
    "Q3/4-PUT.input_validation_id",
    "Q3/4-PUT.input_validation_average",
    "Q3/4-PUT.db_check_exists",
    "Q3/4-PUT.db_update",
    "Q3/4-PUT.response_success",
    "Q3/4-PUT.response_error_not_found",
    "Q3/4-PUT.response_error_validation"
  ],
  "leaf_tasks": [
    {
      "task_id": "Q3/4-PUT.api_validation",
      "description": "הפעלת PUT ב-API מקבלת ת\"ז כפרמטר בנתיב ו ממוצע ציונים כגוף הבקשה",
      "technical_details": "Endpoint: PUT /students/:id, request body: {\"average\": number}"
    },
    {
      "task_id": "Q3/4-PUT.input_validation_id",
      "description": "אימות תקפות ת\"ז: חייב להיות מחרוזת של 10 ספרות",
      "technical_details": "Validate student_id matches regex ^\\d{10}$"
    },
    {
      "task_id": "Q3/4-PUT.input_validation_average",
      "description": "אימות תקפות ממוצע ציונים: חייב להיות מספר בטווח 0-100",
      "technical_details": "Validate average is a number, integer or float, and 0 ≤ average ≤ 100"
    },
    {
      "task_id": "Q3/4-PUT.db_check_exists",
      "description": "בדיקה האם סטודנט עם הת\"ז הנתון קיים במאגר",
      "technical_details": "SELECT 1 FROM students WHERE id = ? LIMIT 1"
    },
    {
      "task_id": "Q3/4-PUT.db_update",
      "description": "עדכון הממוצע של הסטודנט במאגר אם הוא קיים",
      "technical_details": "UPDATE students SET average = ? WHERE id = ?"
    },
    {
      "task_id": "Q3/4-PUT.response_success",
      "description": "החזרת תשובה מוצלחת אם העדכון בוצע",
      "technical_details": "Return HTTP 200 with {\"status\": \"success\", \"message\": \"Average updated\"}"
    },
    {
      "task_id": "Q3/4-PUT.response_error_not_found",
      "description": "החזרת ERROR אם הסטודנט לא קיים",
      "technical_details": "Return HTTP 404 with {\"status\": \"ERROR\", \"message\": \"Student not found\"}"
    },
    {
      "task_id": "Q3/4-PUT.response_error_validation",
      "description": "החזרת ERROR אם האימות של входים נכשל",
      "technical_details": "Return HTTP 400 with {\"status\": \"ERROR\", \"message\": \"Invalid input\"}"
    }
  ]
}

